import {
  isValidElement,
  type HTMLAttributeAnchorTarget,
  type ReactNode,
} from "react";

import { toast as baseToast } from "@/hooks/use-toast";
import type { OdsToastStatus } from "@/components/orderly/OdsToast";

type ToastMessageOptions = {
  actionHref?: string;
  actionLabel?: ReactNode;
  actionTarget?: HTMLAttributeAnchorTarget;
  description?: ReactNode;
  onAction?: () => void;
  title?: ReactNode;
};

const optionKeys: Array<keyof ToastMessageOptions> = [
  "actionHref",
  "actionLabel",
  "actionTarget",
  "description",
  "onAction",
  "title",
];

function messageText(message: unknown) {
  if (typeof message === "string" || isValidElement(message)) {
    return message;
  }

  if (message instanceof Error) {
    return message.message;
  }

  return typeof message === "string" ? message : String(message ?? "");
}

function isToastMessageOptions(
  message: unknown
): message is ToastMessageOptions {
  if (!message || typeof message !== "object" || Array.isArray(message)) {
    return false;
  }

  return optionKeys.some(key => key in message);
}

function createToast(status: OdsToastStatus, message: unknown) {
  const variant = status === "error" ? "destructive" : undefined;

  if (isToastMessageOptions(message)) {
    return baseToast({
      ...message,
      status,
      variant,
    });
  }

  return baseToast({
    title: messageText(message),
    status,
    variant,
  });
}

export const toast = {
  info(message: unknown) {
    return createToast("info", message);
  },
  success(message: unknown) {
    return createToast("success", message);
  },
  warning(message: unknown) {
    return createToast("warning", message);
  },
  error(message: unknown) {
    return createToast("error", message);
  },
};

export { Toaster } from "@/components/ui/toaster";
